(window.webpackJsonp=window.webpackJsonp||[]).push([[424],{1051:function(r,n){r.exports='\x3c!-- \r\ntitle: 01-HTML基础\r\nsort: \r\n--\x3e \r\n# HTML基础\r\n\r\n## 第一个HTML\r\n\r\n```html\r\n<!DOCTYPE html>\r\n<html>\r\n    <head>\r\n\t\t<meta charset="utf-8">\r\n\t\t<title>First</title>\r\n\t</head>\r\n    <body>\r\n        \x3c!-- 声明编码 --\x3e\r\n        <h1>我是一个标题</h1>\r\n        <p>我是一个段落</p>\r\n    </body>\r\n</html>\r\n```\r\n\r\n## 基础标签\r\n\r\n- `<h>`\r\n\r\n- `<a href="https://www.baidu.com"`\r\n\r\n  > 使用`target`定义何处显示\r\n  >\r\n  > `target="_blank"`：新标签页\r\n  >\r\n  > `herf`后跟`#`打开但不跳转\r\n  >\r\n  > `id`可用来跳转至某一位置\r\n\r\n- `<img src="*" width="960" height="720"`\r\n\r\n- `<em> # 斜体`\r\n\r\n- `<strong> # 黑体`\r\n\r\n- `<br> # 换行`\r\n\r\n- `<hr> # 水平线`\r\n\r\n### 属性参考\r\n\r\n| 属性  | 描述             |\r\n| ----- | ---------------- |\r\n| class | .类名（可重复    |\r\n| id    | #唯一的id        |\r\n| style | 样式             |\r\n| title | 额外信息，工具条 |\r\n\r\n### 内联样式\r\n\r\n```html\r\n<body style="background-color:dark">\r\n    <h2 style="background-color:red">H2header</h2>\r\n    <p style="background-color:blue;color:white">\r\n        This is a paragraph<br>\r\n        233333</p>\r\n</body>\r\n\r\n```\r\n\r\n### 内链样式表\r\n\r\n```html\r\n<head>\r\n    <style type="text/css">\r\n    body {background-color:black;}\r\n    p{background-color:red;color:white}\r\n    </style>\r\n</head>\r\n<body>\r\n    <p>\r\n        This is a paragraph<br>\r\n        233333</p>\r\n</body>\r\n\r\n```\r\n\r\n### 外联样式表\r\n\r\n```html\r\n<head>\r\n\t<link rel="stylesheet" type="text/css" href="https://www.w3cschool.cn/html/mystyle.css">\r\n</head> \r\n```\r\n\r\n### 头部\r\n\r\n- 定义基本连接目标\r\n\r\n```html\r\n<head>       \r\n<base href="//www.w3cschool.cn/images/" target="_blank">      \r\n</head>\r\n```\r\n\r\n- `mate`：提供元数据\r\n\r\n  > 每30s刷新界面\r\n  >\r\n  > `<meta http-equiv="refresh" content="30">`'}}]);